10	service AgentNervousSystem {
11	  // ── Session Management ──────────────────────────────────
12	  rpc CreateSession(CreateSessionRequest) returns (Session);
13	  rpc CloseSession(CloseSessionRequest) returns (Empty);
14	  rpc Navigate(NavigateRequest) returns (PageState);
15	  rpc ExecuteAction(ExecuteActionRequest) returns (ActionResult);
16	
17	  // ── Perception ──────────────────────────────────────────
18	  rpc GetDistilledDom(DomRequest) returns (DistilledDom);
19	  rpc CaptureScreenshot(ScreenshotRequest) returns (ScreenshotResponse);
20	  rpc ComputeDiff(DiffRequest) returns (DiffReport);
21	
22	  // ── Goal State ──────────────────────────────────────────
23	  rpc CreateGoal(CreateGoalRequest) returns (GoalState);
24	  rpc GetGoalState(GoalStateRequest) returns (GoalState);
25	  rpc UpdateGoalProgress(ProgressUpdate) returns (GoalState);
26	  rpc SubscribeGoalUpdates(GoalStateRequest) returns (stream GoalUpdate);
27	
28	  // ── Eye Reports (Streaming) ─────────────────────────────
29	  rpc SubmitEyeReports(SubmitReportsRequest) returns (RoutedSignal);
30	  rpc SubscribeEyeReports(SessionRequest) returns (stream EyeReport);
31	
32	  // ── Immune System ───────────────────────────────────────
33	  rpc ClassifyDistractions(DistractionRequest) returns (DistractionList);
34	  rpc ScanInjections(InjectionScanRequest) returns (InjectionScanResult);
35	  rpc CheckAction(ActionCheckRequest) returns (ActionCheckResponse);
36	
37	  // ── Decision Intelligence ───────────────────────────────
38	  rpc StoreScore(StoreScoreRequest) returns (StoreScoreResponse);
39	  rpc QueryBestActions(QueryBestActionsRequest) returns (ScoredActionList);
40	  rpc SearchSimilarDecisions(SearchRequest) returns (ScoredActionList);
41	
42	  // ── Budget ──────────────────────────────────────────────
43	  rpc GetBudgetStatus(BudgetStatusRequest) returns (BudgetStatus);
44	  rpc ConfigureBudget(BudgetConfigRequest) returns (BudgetConfig);
45	
46	  // ── Health ──────────────────────────────────────────────
47	  rpc Health(Empty) returns (HealthStatus);
48	}
