8	/// The Decision Intelligence Layer's unit of memory.
9	///
10	/// After every action executes, the scoring engine produces one of these.
11	/// It's stored in LanceDB and queried by cosine similarity on
12	/// `context_embedding` when the agent faces a similar situation again.
13	#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
14	pub struct DecisionRecord {
15	    /// Unique record identifier.
16	    pub id: Uuid,
17	    /// Session this action was part of.
18	    pub session_id: Uuid,
19	    /// Goal this action was advancing.
20	    pub goal_id: Uuid,
21	    /// The action that was executed.
22	    pub action: Action,
23	    /// The tool used (e.g. "cdp_click", "vision_verify").
24	    pub tool: String,
25	    /// Task-type tag for grouping similar contexts.
26	    pub context_type: String,
27	    /// 768-dim (or 384-dim) embedding of the context at decision time.
28	    pub context_embedding: Vec<f32>,
29	
30	    /// 3-layer business outcome.
31	    pub business_outcome: BusinessOutcome,
32	
33	    /// Did the action itself succeed (no error from CDP)?
34	    pub outcome_success: bool,
35	    /// What did the action produce? (structured summary)
36	    pub results_summary: String,
37	    /// Error message if the action failed.
38	    pub error_message: Option<String>,
39	    /// Composite score: f(outcome, results, errors, business_outcome).
40	    pub composite_score: f32,
41	
42	    /// How many times this (action, tool, context_type) combination has been used.
43	    pub use_count: u32,
44	    /// When this record was created.
45	    pub created_at: DateTime<Utc>,
46	    /// When this record was last updated (e.g. short-term / long-term outcome arrived).
47	    pub updated_at: DateTime<Utc>,
48	}
49	
50	/// 3-layer temporal business outcome model.
51	///
52	/// Each layer answers a different question:
53	/// - **Immediate** (t=0): Did the action work technically?
54	/// - **Short-term** (t=minutes-hours): Did the goal advance in this session?
55	/// - **Long-term** (t=days-months): Did the business outcome materialize?
56	#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
57	pub struct BusinessOutcome {
58	    /// Immediate technical outcome (0.0 = failure, 1.0 = success).
59	    pub immediate: ImmediateOutcome,
60	    /// Short-term session outcome (arrives minutes to hours later).
61	    pub short_term: Option<ShortTermOutcome>,
62	    /// Long-term business impact (arrives days to months later).
63	    pub long_term: Option<LongTermOutcome>,
64	}
65	
66	impl BusinessOutcome {
67	    /// Create a new outcome with only the immediate layer populated.
68	    pub fn new_immediate(success: bool, error: Option<String>) -> Self {
69	        Self {
70	            immediate: ImmediateOutcome {
71	                action_succeeded: success,
72	                results_produced: String::new(),
73	                error_message: error,
74	                execution_time_ms: 0,
75	            },
76	            short_term: None,
77	            long_term: None,
78	        }
79	    }
80	
81	    /// Weighted composite across all populated layers.
82	    pub fn composite_score(&self) -> f32 {
83	        let immediate_weight = 0.6;
84	        let short_term_weight = 0.3;
85	        let long_term_weight = 0.1;
86	
87	        let immediate_score = self.immediate.score();
88	        let mut total = immediate_score * immediate_weight;
89	        let mut weight_sum = immediate_weight;
90	
91	        if let Some(ref st) = self.short_term {
92	            total += st.score() * short_term_weight;
93	            weight_sum += short_term_weight;
94	        }
95	        if let Some(ref lt) = self.long_term {
96	            total += lt.score() * long_term_weight;
97	            weight_sum += long_term_weight;
98	        }
99	
100	        total / weight_sum
101	    }
102	}
103	
104	#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
105	pub struct ImmediateOutcome {
106	    pub action_succeeded: bool,
107	    pub results_produced: String,
108	    pub error_message: Option<String>,
109	    pub execution_time_ms: u64,
110	}
111	
112	impl ImmediateOutcome {
113	    pub fn score(&self) -> f32 {
114	        if self.action_succeeded {
115	            1.0
116	        } else {
117	            // Penalize based on error severity (heuristic).
118	            match &self.error_message {
119	                Some(e) if e.contains("timeout") => 0.2,
120	                Some(e) if e.contains("not found") => 0.1,
121	                Some(_) => 0.0,
122	                None => 0.5,
123	            }
124	        }
125	    }
126	}
