1	//! Layer 1 External API Gateway.
2	//!
3	//! How external AI agents connect to the Agent Nervous System.
4	//! Three protocols, one gateway:
5	//!
6	//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
7	//!   for Claude, ChatGPT, and other MCP-compatible agents.
8	//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
9	//! - **WebSocket**: Streaming events for real-time agent feedback.
10	//!
11	//! All connections are authenticated (API key), rate-limited, and
12	//! budget-tracked before any internal gRPC call is made.
13	
14	pub mod auth;
15	pub mod client;
16	pub mod mcp;
17	pub mod rest;
18	pub mod ws;
19	
20	use std::net::SocketAddr;
21	use std::sync::Arc;
22	
23	use axum::routing::{get, post};
24	use axum::Router;
25	
26	use auth::SharedKeyRegistry;
27	use client::InternalClient;
28	use mcp::McpServer;
29	use rest::ApiRouter;
30	use ws::WebSocketServer;
31	
32	/// Shared gateway state, created once at startup.
33	#[derive(Clone)]
34	pub struct Gateway {
35	    key_registry: SharedKeyRegistry,
36	    mcp: McpServer,
37	    rest: ApiRouter,
38	    ws: WebSocketServer,
39	}
40	
41	impl Gateway {
42	    /// Initialize the gateway: load API keys, connect to the daemon.
43	    pub async fn init() -> Result<Self, Box<dyn std::error::Error>> {
44	        let key_registry = Arc::new(auth::KeyRegistry::load(None)?);
45	        let internal = InternalClient::connect().await?;
46	        let mcp = McpServer::new(internal.clone());
47	        let rest = ApiRouter::new(internal.clone());
48	        let ws = WebSocketServer::new(internal.clone());
49	
50	        Ok(Self {
51	            key_registry,
52	            mcp,
53	            rest,
54	            ws,
55	        })
56	    }
57	
58	    /// Build the axum router with all routes mounted and auth applied.
59	    pub fn router(&self) -> Router {
60	        let mcp = self.mcp.clone();
61	        let rest = self.rest.clone();
62	        let ws = self.ws.clone();
63	        let auth_layer = auth::AuthLayer::new(Arc::clone(&self.key_registry));
64	
65	        // Health endpoint — no auth required
66	        let health_rest = rest.clone();
67	        let router = Router::new()
68	            // MCP endpoint — no auth (MCP clients authenticate via headers differently)
69	            .route(
70	                "/mcp",
71	                post(
72	                    move |body: axum::extract::Json<serde_json::Value>| async move {
73	                        let response = mcp.handle_request(body.0).await;
74	                        axum::Json(response)
75	                    },
76	                ),
77	            )
78	            // WebSocket upgrade — auth handled during handshake
79	            .route(
80	                "/ws",
81	                get(
82	                    move |ws_upgrade: axum::extract::ws::WebSocketUpgrade| async move {
83	                        ws.handle_upgrade(ws_upgrade).await
84	                    },
85	                ),
86	            )
87	            // Public health endpoint — no auth
88	            .route(
89	                "/api/v1/health",
90	                get(move || {
91	                    let rest = health_rest.clone();
92	                    async move { rest.health().await }
93	                }),
94	            )
95	            // Protected REST API — auth applied
96	            .nest(
97	                "/api/v1",
98	                Router::new()
99	                    .route(
100	                        "/sessions",
101	                        post({
102	                            let rest = rest.clone();
103	                            move |axum::extract::Json(body): axum::extract::Json<
104	                                serde_json::Value,
105	                            >| async move { rest.create_session(body).await }
106	                        }),
107	                    )
108	                    .route(
109	                        "/sessions/{id}/navigate",
110	                        post({
111	                            let rest = rest.clone();
112	                            move |axum::extract::Path(id): axum::extract::Path<String>,
113	                                  axum::extract::Json(body): axum::extract::Json<
114	                                serde_json::Value,
115	                            >| async move { rest.navigate(&id, body).await }
116	                        }),
117	                    )
118	                    .route(
119	                        "/sessions/{id}/execute",
120	                        post({
121	                            let rest = rest.clone();
122	                            move |axum::extract::Path(id): axum::extract::Path<String>,
123	                                  axum::extract::Json(body): axum::extract::Json<
124	                                serde_json::Value,
125	                            >| async move {
126	                                rest.execute_action(&id, body).await
127	                            }
128	                        }),
129	                    )
130	                    .route(
131	                        "/sessions/{id}/screenshot",
132	                        post({
133	                            let rest = rest.clone();
134	                            move |axum::extract::Path(id): axum::extract::Path<String>,
135	                                  axum::extract::Json(body): axum::extract::Json<
136	                                serde_json::Value,
137	                            >| async move {
138	                                rest.screenshot(&id, body).await
139	                            }
140	                        }),
141	                    )
142	                    .route(
143	                        "/sessions/{id}/dom",
144	                        get({
145	                            let rest = rest.clone();
146	                            move |axum::extract::Path(id): axum::extract::Path<String>| async move {
147	                                rest.get_dom(&id).await
148	                            }
149	                        }),
150	                    )
151	                    .route(
152	                        "/goals",
153	                        post({
154	                            let rest = rest.clone();
155	                            move |axum::extract::Json(body): axum::extract::Json<
156	                                serde_json::Value,
157	                            >| async move { rest.create_goal(body).await }
158	                        }),
159	                    )
160	                    .route(
161	                        "/goals/{id}",
162	                        get({
163	                            let rest = rest.clone();
164	                            move |axum::extract::Path(id): axum::extract::Path<String>| async move {
165	                                rest.get_goal(&id).await
166	                            }
167	                        }),
168	                    )
169	                    .layer(auth_layer),
170	            );
171	        router
172	    }
173	
174	    /// Start the gateway HTTP server on the given address.
175	    /// Blocks until the server exits.
176	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
177	        let router = self.router();
178	
179	        tracing::info!("Gateway starting on {}", addr);
180	
181	        let listener = tokio::net::TcpListener::bind(addr).await?;
182	        axum::serve(listener, router).await?;
183	
184	        Ok(())
185	    }
186	}
